    34→#ifdef EN_PERF
    35→static volatile float g_acc;
    36→static int g_ex;
    37→
    38→static void emit(float x)
    39→{
    40→    volatile float vx = x;  /* prevent constant-folding of literal arguments */
    41→    g_acc += frexpf(vx, &g_ex);
    42→}
    43→
    44→static void emit_u(uint32_t bits)
    45→{
    46→    emit(u2f(bits));
    47→}
    48→#else
    49→static void emit(float x)
    50→{
    51→    int ex;
    52→    float r = frexpf(x, &ex);
    53→    printf("%08lx %08lx %d\n",
    54→           (unsigned long)f2u(x), (unsigned long)f2u(r), ex);
    55→}
    56→
    57→static void emit_u(uint32_t bits)
    58→{
    59→    emit(u2f(bits));
    60→}
