    63→/* ------------------------------------------------------------------ */
    64→/* Representative 100-point test                                       */
    65→/* ------------------------------------------------------------------ */
    66→
    67→static void test_representative_100(void)
    68→{
    69→    /* --- Section 1: Special IEEE 754 values (7) --- */
    70→    emit(0.0f);
    71→    emit(-0.0f);
    72→    emit_u(0x7fc00000u);  /* qNaN */
    73→    emit_u(0x7f800001u);  /* sNaN */
    74→    emit_u(0xffc00000u);  /* -qNaN */
    75→    emit_u(0x7f800000u);  /* +Inf */
    76→    emit_u(0xff800000u);  /* -Inf */
    77→
    78→    /* --- Section 2: Subnormal (denormal) values (6) --- */
    79→    emit_u(0x00000001u);  /* min positive subnormal: 2^-149 */
    80→    emit_u(0x80000001u);  /* min negative subnormal */
    81→    emit_u(0x00400000u);  /* mid positive subnormal */
    82→    emit_u(0x80400000u);  /* mid negative subnormal */
    83→    emit_u(0x007fffffu);  /* max subnormal: just below FLT_MIN */
    84→    emit_u(0x807fffffu);  /* max negative subnormal */
    85→
    86→    /* --- Section 3: Normal boundary values (6) --- */
    87→    emit(FLT_MIN);                /* 2^-126, smallest normal */
    88→    emit(-FLT_MIN);
    89→    emit_u(0x00800001u);          /* one ULP above FLT_MIN */
    90→    emit_u(0x7f7fffffu);          /* FLT_MAX */
    91→    emit_u(0xff7fffffu);          /* -FLT_MAX */
    92→    emit_u(0x7f7ffffeu);          /* one ULP below FLT_MAX */
    93→
    94→    /* --- Section 4: Near 1.0 ULP density (8) --- */
    95→    emit_u(0x3f7fffffu);  /* one ULP below 1.0 */
    96→    emit(1.0f);           /* 1.0 -> mantissa=0.5, exp=1 */
    97→    emit_u(0x3f800001u);  /* one ULP above 1.0 */
    98→    emit_u(0x3f7ffff0u);  /* a few ULPs below 1.0 */
    99→    emit_u(0x3f800010u);  /* a few ULPs above 1.0 */
   100→    emit(-1.0f);
   101→    emit_u(0xbf7fffffu);  /* one ULP toward zero from -1.0 */
   102→    emit_u(0xbf800001u);  /* one ULP away from zero from -1.0 */
   103→
   104→    /* --- Section 5: Powers of 2 (exponent switching points) (16) --- */
   105→    emit_u(0x3a800000u);  /* 2^-10 */
   106→    emit_u(0x3b000000u);  /* 2^-9 */
   107→    emit_u(0x3b800000u);  /* 2^-8 */
   108→    emit_u(0x3c000000u);  /* 2^-7 */
   109→    emit_u(0x3c800000u);  /* 2^-6 */
   110→    emit_u(0x3d000000u);  /* 2^-5 */
   111→    emit_u(0x3d800000u);  /* 2^-4 */
   112→    emit_u(0x3e000000u);  /* 2^-3 = 0.125 */
   113→    emit_u(0x3e800000u);  /* 2^-2 = 0.25 */
   114→    emit_u(0x3f000000u);  /* 2^-1 = 0.5 */
   115→    emit_u(0x3f800000u);  /* 2^0  = 1.0 */
   116→    emit_u(0x40000000u);  /* 2^1  = 2.0 */
   117→    emit_u(0x40800000u);  /* 2^2  = 4.0 */
   118→    emit_u(0x41000000u);  /* 2^3  = 8.0 */
   119→    emit_u(0x41800000u);  /* 2^4  = 16.0 */
   120→    emit_u(0x42000000u);  /* 2^5  = 32.0 */
