   122→    /* --- Section 6: Exact mantissa fractions (positive) (12) --- */
   123→    emit(0.5f);    /* mantissa=0.5, exp=0 */
   124→    emit(0.625f);  /* 0.5 * 1.25, exp=0 */
   125→    emit(0.75f);   /* 0.5 * 1.5, exp=0 */
   126→    emit(0.875f);  /* 0.5 * 1.75, exp=0 */
   127→    emit(1.25f);   /* mantissa=0.625, exp=1 */
   128→    emit(1.5f);    /* mantissa=0.75, exp=1 */
   129→    emit(1.75f);   /* mantissa=0.875, exp=1 */
   130→    emit(3.0f);    /* mantissa=0.75, exp=2 */
   131→    emit(5.0f);    /* mantissa=0.625, exp=3 */
   132→    emit(6.0f);    /* mantissa=0.75, exp=3 */
   133→    emit(7.0f);    /* mantissa=0.875, exp=3 */
   134→    emit(100.0f);  /* mantissa=0.78125, exp=7 */
   135→
   136→    /* --- Section 7: Negative mirrors of section 6 (12) --- */
   137→    emit(-0.5f);
   138→    emit(-0.625f);
   139→    emit(-0.75f);
   140→    emit(-0.875f);
   141→    emit(-1.25f);
   142→    emit(-1.5f);
   143→    emit(-1.75f);
   144→    emit(-3.0f);
   145→    emit(-5.0f);
   146→    emit(-6.0f);
   147→    emit(-7.0f);
   148→    emit(-100.0f);
   149→
   150→    /* --- Section 8: Large values (10) --- */
   151→    emit(1.0e3f);
   152→    emit(-1.0e3f);
   153→    emit(1.0e7f);
   154→    emit(-1.0e7f);
   155→    emit(1.0e10f);
   156→    emit(-1.0e10f);
   157→    emit(1.0e20f);
   158→    emit(-1.0e20f);
   159→    emit(1.0e30f);
   160→    emit(-1.0e30f);
   161→
   162→    /* --- Section 9: Small normal values (10) --- */
   163→    emit(1.0e-10f);
   164→    emit(-1.0e-10f);
   165→    emit(1.0e-20f);
   166→    emit(-1.0e-20f);
   167→    emit(1.0e-30f);
   168→    emit(-1.0e-30f);
   169→    emit_u(0x00800002u);  /* two ULPs above FLT_MIN */
   170→    emit_u(0x80800002u);  /* two ULPs above -FLT_MIN toward zero */
   171→    emit_u(0x01000000u);  /* 2^-126 * 2 = 2^-125: first normal with exp field 2 */
   172→    emit_u(0x81000000u);  /* negative of above */
   173→
   174→    /* --- Section 10: ULP neighbors of key mantissa boundaries (13) --- */
   175→    emit_u(0x3effffffu);  /* one ULP below 0.5 */
   176→    emit_u(0x3f000001u);  /* one ULP above 0.5 */
   177→    emit_u(0x3f7ffffeu);  /* two ULPs below 1.0 */
   178→    emit_u(0x3f800002u);  /* two ULPs above 1.0 */
   179→    emit_u(0x3fffffffu);  /* one ULP below 2.0 */
   180→    emit_u(0x40000001u);  /* one ULP above 2.0 */
   181→    emit_u(0x407fffffu);  /* one ULP below 4.0 */
   182→    emit_u(0x40800001u);  /* one ULP above 4.0 */
   183→    emit_u(0x3f400000u);  /* 0.75: mid-point of [0.5, 1) */
   184→    emit_u(0x3f600000u);  /* 0.875 */
   185→    emit_u(0x3f200000u);  /* 0.625 */
   186→    emit_u(0xbf400000u);  /* -0.75 */
   187→    emit_u(0xbf600000u);  /* -0.875 */
