   192→/* 7. Sweep [0.5, 2) mantissa range with integer base exponents */
   193→static void test_sweep(void)
   194→{
   195→    float lo = 0.5f, hi = 2.0f;
   196→    int nsteps = 100;
   197→    float step = (hi - lo) / (float)nsteps;
   198→
   199→    for (int i = 0; i <= nsteps; i++)
   200→        emit(lo + (float)i * step);
   201→
   202→    /* Negative */
   203→    for (int i = 0; i <= nsteps; i++)
   204→        emit(-(lo + (float)i * step));
   205→}
   206→
   207→/* 8. Sample [0.5, 1] every 2097152 ULP (~250 cases) */
   208→static void test_exhaustive_small(void)
   209→{
   210→    uint32_t start = 0x3f000000u; /* 0.5 */
   211→    uint32_t end = 0x3f800000u;   /* 1.0 */
   212→    for (uint32_t b = start; b <= end; b += 2097152)
   213→        emit_u(b);
   214→}
